/// Render a single PDF page to PNG bytes.
///
/// Returns raw PNG-encoded bytes for the specified page at the given DPI.
/// Uses pdf_oxide with tiny-skia for pure-Rust rendering.
///
/// # Arguments
///
/// * `pdf_bytes` - Raw PDF file bytes
/// * `page_index` - Zero-based page index
/// * `dpi` - Resolution in dots per inch (default: 150)
/// * `password` - Optional password for encrypted PDFs
///
/// # Errors
///
/// Returns `KreuzbergError.Parsing` if the PDF cannot be opened, authenticated,
/// or rendered, or if `page_index` is out of range.
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "renderPdfPageToPng")]
pub fn render_pdf_page_to_png(
    pdf_bytes: Vec<u8>,
    page_index: usize,
    dpi: Option<i32>,
    password: Option<String>,
) -> Result<Vec<u8>, JsValue> {
    let result = kreuzberg::render_pdf_page_to_png(&pdf_bytes, page_index, dpi, password.as_deref())
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result)
}

/// Detect the MIME type of a file at the given path.
///
/// Uses the file extension and optionally the file content to determine the MIME type.
/// Set `check_exists` to `true` to verify the file exists before detection.
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "detectMimeType")]
pub fn detect_mime_type(path: String, check_exists: bool) -> Result<String, JsValue> {
    let result = kreuzberg::detect_mime_type(path, check_exists).map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result)
}

